### Set Encrypted Session Cookie in Next.js Pages Router API Route

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/authentication.mdx

This API route handler encrypts session data from the request body and sets it as an `httpOnly` and `secure` cookie. It uses the `cookie` library for serialization and is suitable for login authentication in Next.js Pages Router.

```ts
import { serialize } from 'cookie'
import type { NextApiRequest, NextApiResponse } from 'next'
import { encrypt } from '@/app/lib/session'

export default function handler(req: NextApiRequest, res: NextApiResponse) {
  const sessionData = req.body
  const encryptedSessionData = encrypt(sessionData)

  const cookie = serialize('session', encryptedSessionData, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    maxAge: 60 * 60 * 24 * 7, // One week
    path: '/',
  })
  res.setHeader('Set-Cookie', cookie)
  res.status(200).json({ message: 'Successfully set cookie!' })
}
```

