### Configure Next.js Proxy for Authentication-Based Rewrites

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/03-api-reference/02-components/link.mdx

This snippet demonstrates how to set up a Next.js Proxy to conditionally rewrite the `/dashboard` route. It checks for an `authToken` cookie in the request and redirects authenticated users to `/auth/dashboard` and unauthenticated users to `/public/dashboard` using `NextResponse.rewrite`.

```ts
import { NextResponse } from 'next/server'

export function proxy(request: Request) {
  const nextUrl = request.nextUrl
  if (nextUrl.pathname === '/dashboard') {
    if (request.cookies.authToken) {
      return NextResponse.rewrite(new URL('/auth/dashboard', request.url))
    } else {
      return NextResponse.rewrite(new URL('/public/dashboard', request.url))
    }
  }
}
```

